import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonDoubleAdapterTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void testDoubleAdapter_SerializeSpecialFloatingPointValuesTrue_ReturnsTypeAdaptersDouble() throws Exception {
    Method method = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    method.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) method.invoke(gson, true);

    assertSame(TypeAdapters.DOUBLE, adapter);
  }

  @Test
  void testDoubleAdapter_SerializeSpecialFloatingPointValuesFalse_ReadNull() throws Exception {
    Method method = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    method.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) method.invoke(gson, false);

    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenReturn(JsonToken.NULL);

    Double result = adapter.read(reader);

    verify(reader).nextNull();
    assertNull(result);
  }

  @Test
  void testDoubleAdapter_SerializeSpecialFloatingPointValuesFalse_ReadDouble() throws Exception {
    Method method = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    method.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) method.invoke(gson, false);

    JsonReader reader = mock(JsonReader.class);
    when(reader.peek()).thenReturn(JsonToken.NUMBER);
    when(reader.nextDouble()).thenReturn(123.456);

    Double result = adapter.read(reader);

    assertEquals(123.456, result);
  }

  @Test
  void testDoubleAdapter_SerializeSpecialFloatingPointValuesFalse_WriteNull() throws Exception {
    Method method = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    method.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) method.invoke(gson, false);

    JsonWriter writer = mock(JsonWriter.class);

    adapter.write(writer, null);

    verify(writer).nullValue();
  }

  @Test
  void testDoubleAdapter_SerializeSpecialFloatingPointValuesFalse_WriteValidDouble() throws Exception {
    Method method = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    method.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) method.invoke(gson, false);

    JsonWriter writer = mock(JsonWriter.class);

    // Use a valid double value
    Number value = 45.67;

    // We need to mock checkValidFloatingPoint call - it's static and package-private
    // but since it throws on invalid values only, we can test with valid value safely

    adapter.write(writer, value);

    verify(writer).value(value.doubleValue());
  }

  @Test
  void testDoubleAdapter_SerializeSpecialFloatingPointValuesFalse_WriteInvalidDouble_NaN() throws Exception {
    Method method = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    method.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) method.invoke(gson, false);

    JsonWriter writer = mock(JsonWriter.class);

    Number value = Double.NaN;

    // The checkValidFloatingPoint should throw IllegalArgumentException for NaN
    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> adapter.write(writer, value));
    assertTrue(thrown.getMessage().contains("NaN"));
  }

  @Test
  void testDoubleAdapter_SerializeSpecialFloatingPointValuesFalse_WriteInvalidDouble_PositiveInfinity() throws Exception {
    Method method = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    method.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) method.invoke(gson, false);

    JsonWriter writer = mock(JsonWriter.class);

    Number value = Double.POSITIVE_INFINITY;

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> adapter.write(writer, value));
    assertTrue(thrown.getMessage().contains("Infinity"));
  }

  @Test
  void testDoubleAdapter_SerializeSpecialFloatingPointValuesFalse_WriteInvalidDouble_NegativeInfinity() throws Exception {
    Method method = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    method.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) method.invoke(gson, false);

    JsonWriter writer = mock(JsonWriter.class);

    Number value = Double.NEGATIVE_INFINITY;

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> adapter.write(writer, value));
    assertTrue(thrown.getMessage().contains("Infinity"));
  }
}
